CREATE TABLE hairtype (
    hairtype_id SERIAL PRIMARY KEY,
    hairtype_name VARCHAR(100) NOT NULL UNIQUE
);

CREATE TABLE product_type (
    product_type_id SERIAL PRIMARY KEY,
    product_type_name VARCHAR(100) NOT NULL UNIQUE
);

CREATE TABLE purpose (
    purpose_id SERIAL PRIMARY KEY,
    purpose_name VARCHAR(100) NOT NULL UNIQUE
);

CREATE TABLE person (
    person_id SERIAL PRIMARY KEY,
    username VARCHAR(100) NOT NULL,
    email VARCHAR(255) NOT NULL UNIQUE,
    password VARCHAR(100) NOT NULL,
    role VARCHAR(20) NOT NULL CHECK (role IN ('ADMIN', 'USER')),
    hairtype_id INTEGER
        REFERENCES hairtype(hairtype_id)
        ON DELETE SET NULL
);

CREATE TABLE ingredient (
    ingredient_id SERIAL PRIMARY KEY,
    ingredient_name VARCHAR(255) NOT NULL UNIQUE,
    purpose_id INTEGER NOT NULL
        REFERENCES purpose(purpose_id)
        ON DELETE CASCADE
);

CREATE TABLE product (
    product_id SERIAL PRIMARY KEY,
    product_name VARCHAR(255) NOT NULL,
    product_type_id INTEGER
        REFERENCES product_type(product_type_id)
        ON DELETE SET NULL,
    ingredients_list TEXT[] NOT NULL,
    pic_url TEXT NOT NULL,
    price_category VARCHAR(50) NOT NULL
);

CREATE TABLE relevant_range (
    relevant_range_id SERIAL PRIMARY KEY,
    purpose_id INTEGER NOT NULL
        REFERENCES purpose(purpose_id)
        ON DELETE CASCADE,
    hairtype_id INTEGER NOT NULL
        REFERENCES hairtype(hairtype_id)
        ON DELETE CASCADE,
    min_value INTEGER NOT NULL CHECK (min_value >= 0),
    max_value INTEGER NOT NULL CHECK (max_value >= 0),
    CHECK (min_value <= max_value),
    UNIQUE (purpose_id, hairtype_id)
);

CREATE TABLE person_result (
    person_result_id SERIAL PRIMARY KEY,
    person_id INTEGER NOT NULL
        REFERENCES person(person_id)
        ON DELETE CASCADE,
    hairtype_id INTEGER NOT NULL
        REFERENCES hairtype(hairtype_id)
        ON DELETE CASCADE,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE product_class_score (
    product_class_score_id SERIAL PRIMARY KEY,
    product_id INTEGER NOT NULL
        REFERENCES product(product_id)
        ON DELETE CASCADE,
    purpose_id INTEGER NOT NULL
        REFERENCES purpose(purpose_id)
        ON DELETE CASCADE,
    score INTEGER NOT NULL CHECK (score >= 0),
    UNIQUE (product_id, purpose_id)
);

CREATE TABLE product_suitability (
    product_id INTEGER NOT NULL
        REFERENCES product(product_id)
        ON DELETE CASCADE,
    hairtype_id INTEGER NOT NULL
        REFERENCES hairtype(hairtype_id)
        ON DELETE CASCADE,
    PRIMARY KEY (product_id, hairtype_id)
);




